import java.util.*;

public class GraphDFS {

    public List<Integer> dfs(Map<Integer, List<Integer>> graph, int start) {
        List<Integer> order = new ArrayList<>();
        Set<Integer> visited = new HashSet<>();
        dfsHelper(graph, start, visited, order);
        return order;
    }

    private void dfsHelper(Map<Integer, List<Integer>> graph, int node,
                           Set<Integer> visited, List<Integer> order) {
        visited.add(node);
        order.add(node);
        for (int neighbor : graph.getOrDefault(node, Collections.emptyList())) {
            if (!visited.contains(neighbor)) dfsHelper(graph, neighbor, visited, order);
        }
    }

    public boolean hasPath(Map<Integer, List<Integer>> graph, int src, int dst) {
        // TODO: DFS from src, return true if dst is reached
        return false;
    }

    public Set<Integer> reachable(Map<Integer, List<Integer>> graph, int src) {
        // TODO: return set of all nodes reachable from src (not including src itself)
        return new HashSet<>();
    }

    public static void main(String[] args) {
        Map<Integer, List<Integer>> g = new LinkedHashMap<>();
        g.put(0, Arrays.asList(1, 2));
        g.put(1, Arrays.asList(0, 3, 4));
        g.put(2, Arrays.asList(0));
        g.put(3, Arrays.asList(1));
        g.put(4, Arrays.asList(1));
        GraphDFS gd = new GraphDFS();
        System.out.println("DFS from 0: " + gd.dfs(g, 0));
        System.out.println("hasPath(0,4): " + gd.hasPath(g, 0, 4));
        System.out.println("hasPath(2,3): " + gd.hasPath(g, 2, 3));
        System.out.println("Reachable from 0: " + new TreeSet<>(gd.reachable(g, 0)));
    }
}

import java.util.*;

public class GraphBFS {

    public List<Integer> shortestPath(Map<Integer, List<Integer>> graph, int src, int dst) {
        Map<Integer, Integer> parent = new HashMap<>();
        Queue<Integer> queue = new LinkedList<>();
        Set<Integer> visited = new HashSet<>();
        queue.add(src); visited.add(src); parent.put(src, -1);

        while (!queue.isEmpty()) {
            int curr = queue.poll();
            if (curr == dst) break;
            for (int nb : graph.getOrDefault(curr, Collections.emptyList())) {
                if (!visited.contains(nb)) {
                    visited.add(nb); queue.add(nb); parent.put(nb, curr);
                }
            }
        }
        // TODO: reconstruct path from dst back to src using parent map
        return new ArrayList<>();
    }

    public Map<Integer, Integer> bfsDistances(Map<Integer, List<Integer>> graph, int src) {
        // TODO: return map of vertex -> distance from src (BFS level)
        return new HashMap<>();
    }

    public static void main(String[] args) {
        Map<Integer, List<Integer>> g = new LinkedHashMap<>();
        g.put(1, Arrays.asList(2, 3));
        g.put(2, Arrays.asList(1, 4));
        g.put(3, Arrays.asList(1, 4, 5));
        g.put(4, Arrays.asList(2, 3, 6));
        g.put(5, Arrays.asList(3));
        g.put(6, Arrays.asList(4));
        GraphBFS gb = new GraphBFS();
        System.out.println("Path 1->6: " + gb.shortestPath(g, 1, 6));
        System.out.println("Distances from 1: " + new TreeMap<>(gb.bfsDistances(g, 1)));
    }
}

import java.util.*;

public class CycleDetector {

    public boolean hasCycle(Map<Integer, List<Integer>> graph) {
        Set<Integer> visited = new HashSet<>();
        for (int vertex : graph.keySet()) {
            if (!visited.contains(vertex)) {
                if (dfs(graph, vertex, -1, visited)) return true;
            }
        }
        return false;
    }

    private boolean dfs(Map<Integer, List<Integer>> graph, int node, int parent,
                        Set<Integer> visited) {
        visited.add(node);
        for (int neighbor : graph.getOrDefault(node, Collections.emptyList())) {
            if (!visited.contains(neighbor)) {
                if (dfs(graph, neighbor, node, visited)) return true;
            } else if (neighbor != parent) {
                // TODO: found a back edge -> cycle exists, return true
            }
        }
        return false;
    }

    public static void main(String[] args) {
        CycleDetector cd = new CycleDetector();
        // Cyclic graph: 0-1-2-0
        Map<Integer, List<Integer>> cyclic = new LinkedHashMap<>();
        cyclic.put(0, Arrays.asList(1, 2));
        cyclic.put(1, Arrays.asList(0, 2));
        cyclic.put(2, Arrays.asList(1, 0));
        System.out.println("Cyclic: " + cd.hasCycle(cyclic));
        // Acyclic graph: tree 0-1, 0-2, 1-3
        Map<Integer, List<Integer>> tree = new LinkedHashMap<>();
        tree.put(0, Arrays.asList(1, 2));
        tree.put(1, Arrays.asList(0, 3));
        tree.put(2, Arrays.asList(0));
        tree.put(3, Arrays.asList(1));
        System.out.println("Tree (acyclic): " + cd.hasCycle(tree));
    }
}
